import { writeFileSync, mkdirSync } from "fs";
import { join, dirname } from "path";
const R = process.cwd();
const full = join(R, "src/routes/admin.website.tsx");
mkdirSync(dirname(full), { recursive: true });
writeFileSync(full, Buffer.from("", "base64"), "utf8");
console.log("OK src/routes/admin.website.tsx restored — page should load now");
